package com.itheima.mapper;

import com.itheima.pojo.OperateLog;
import org.apache.ibatis.annotations.Mapper;
import org.apache.ibatis.annotations.Select;

import java.util.List;

@Mapper
public interface LogMapper {

    @Select("select * from emp_log order by operate_time desc, id desc")
    List<OperateLog> page();
}

package com.itheima.mapper;

import com.itheima.pojo.OperateLog;
import org.apache.ibatis.annotations.Mapper;
import org.apache.ibatis.annotations.Select;

import java.util.List;

@Mapper
public interface LogMapper {

    @Select("select ol.id, ol.operate_emp_id, ol.operate_time, ol.class_name, ol.method_name, ol.method_params, " +
            "ol.return_value, ol.cost_time, e.name as operate_emp_name " +
            "from operate_log ol left join emp e on ol.operate_emp_id = e.id " +
            "order by ol.operate_time desc, ol.id desc")
    List<OperateLog> page();
}

package com.itheima.aop;

import com.itheima.mapper.OperateLogMapper;
import com.itheima.pojo.OperateLog;
import com.itheima.utils.CurrentHolder;
import lombok.extern.slf4j.Slf4j;
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.Around;
import org.aspectj.lang.annotation.Aspect;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;
import java.util.Arrays;

@Slf4j
@Aspect
@Component
public class OperationLogAspect {

    private static final int CLASS_NAME_MAX_LEN = 255;
    private static final int METHOD_NAME_MAX_LEN = 100;
    private static final int METHOD_PARAMS_MAX_LEN = 2000;
    private static final int RETURN_VALUE_MAX_LEN = 1000;

    @Autowired
    private OperateLogMapper operateLogMapper;

    // 全量记录 controller 层操作
    @Around("execution(* com.itheima.controller..*(..))")
    public Object around(ProceedingJoinPoint joinPoint) throws Throwable {
        long startTime = System.currentTimeMillis();
        Object result = null;
        Throwable throwable = null;
        try {
            result = joinPoint.proceed();
            return result;
        } catch (Throwable ex) {
            throwable = ex;
            throw ex;
        } finally {
            OperateLog operateLog = new OperateLog();
            operateLog.setOperateEmpId(getCurrentUserId());
            operateLog.setOperateTime(LocalDateTime.now());
            operateLog.setClassName(truncate(joinPoint.getTarget().getClass().getName(), CLASS_NAME_MAX_LEN));
            operateLog.setMethodName(truncate(joinPoint.getSignature().getName(), METHOD_NAME_MAX_LEN));
            operateLog.setMethodParams(truncate(Arrays.toString(joinPoint.getArgs()), METHOD_PARAMS_MAX_LEN));

            String returnValue = (throwable == null) ? String.valueOf(result) : throwable.getClass().getSimpleName() + ": " + throwable.getMessage();
            operateLog.setReturnValue(truncate(returnValue, RETURN_VALUE_MAX_LEN));
            operateLog.setCostTime(System.currentTimeMillis() - startTime);

            try {
                operateLogMapper.insert(operateLog);
            } catch (Exception e) {
                // 日志落库失败不影响主业务
                log.warn("操作日志写入失败, class={}, method={}", operateLog.getClassName(), operateLog.getMethodName(), e);
            }
        }
    }

    private Integer getCurrentUserId() {
        return CurrentHolder.getCurrentId();
    }

    private String truncate(String value, int maxLen) {
        if (value == null || value.length() <= maxLen) {
            return value;
        }
        return value.substring(0, maxLen);
    }
}

package com.itheima.aop;

import com.itheima.mapper.OperateLogMapper;
import com.itheima.pojo.LoginInfo;
import com.itheima.pojo.OperateLog;
import com.itheima.pojo.Result;
import com.itheima.utils.CurrentHolder;
import lombok.extern.slf4j.Slf4j;
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.Around;
import org.aspectj.lang.annotation.Aspect;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;
import java.util.Arrays;

@Slf4j
@Aspect
@Component
public class OperationLogAspect {

    private static final int CLASS_NAME_MAX_LEN = 255;
    private static final int METHOD_NAME_MAX_LEN = 100;
    private static final int METHOD_PARAMS_MAX_LEN = 2000;
    private static final int RETURN_VALUE_MAX_LEN = 1000;

    @Autowired
    private OperateLogMapper operateLogMapper;

    // 全量记录 controller 层操作
    @Around("execution(* com.itheima.controller..*(..))")
    public Object around(ProceedingJoinPoint joinPoint) throws Throwable {
        long startTime = System.currentTimeMillis();
        Object result = null;
        Throwable throwable = null;
        try {
            result = joinPoint.proceed();
            return result;
        } catch (Throwable ex) {
            throwable = ex;
            throw ex;
        } finally {
            OperateLog operateLog = new OperateLog();
            operateLog.setOperateEmpId(resolveOperatorId(result));
            operateLog.setOperateTime(LocalDateTime.now());
            operateLog.setClassName(truncate(joinPoint.getTarget().getClass().getName(), CLASS_NAME_MAX_LEN));
            operateLog.setMethodName(truncate(joinPoint.getSignature().getName(), METHOD_NAME_MAX_LEN));
            operateLog.setMethodParams(truncate(Arrays.toString(joinPoint.getArgs()), METHOD_PARAMS_MAX_LEN));

            String returnValue = (throwable == null) ? String.valueOf(result) : throwable.getClass().getSimpleName() + ": " + throwable.getMessage();
            operateLog.setReturnValue(truncate(returnValue, RETURN_VALUE_MAX_LEN));
            operateLog.setCostTime(System.currentTimeMillis() - startTime);

            try {
                operateLogMapper.insert(operateLog);
            } catch (Exception e) {
                // 日志落库失败不影响主业务
                log.warn("操作日志写入失败, class={}, method={}", operateLog.getClassName(), operateLog.getMethodName(), e);
            }
        }
    }

    private Integer resolveOperatorId(Object result) {
        Integer currentId = CurrentHolder.getCurrentId();
        if (currentId != null) {
            return currentId;
        }

        // 登录接口没有 token，尝试从登录响应中提取操作人ID
        if (result instanceof Result apiResult && apiResult.getData() instanceof LoginInfo loginInfo) {
            return loginInfo.getId();
        }
        return null;
    }

    private String truncate(String value, int maxLen) {
        if (value == null || value.length() <= maxLen) {
            return value;
        }
        return value.substring(0, maxLen);
    }
}

